from typing import List
from collections import defaultdict

class Solution:
    def maximumCost(self, n: int, highways: List[List[int]], k: int) -> int:
        # Build the graph
        graph = defaultdict(list)
        for u, v, toll in highways:
            graph[u].append((v, toll))
            graph[v].append((u, toll))

        # DP table: dp[i][j] = max cost to reach city j with i steps
        # Initialize with -infinity
        dp = [[-1] * n for _ in range(k + 1)]

        # Initialize with 0 steps (no movement), cost is 0
        for i in range(n):
            dp[0][i] = 0

        # Iterate over number of steps from 1 to k
        for steps in range(1, k + 1):
            for city in range(n):
                if dp[steps - 1][city] == -1:
                    continue
                for neighbor, toll in graph[city]:
                    if dp[steps][neighbor] < dp[steps - 1][city] + toll:
                        dp[steps][neighbor] = dp[steps - 1][city] + toll

        # Find the maximum cost among all cities with exactly k steps
        max_cost = max(dp[k])
        return max_cost if max_cost != -1 else -1
