class Solution:
    def strWithout3a3b(self, a: int, b: int) -> str:
        result = []
        while a > 0 or b > 0:
            if a > b:
                # Add two 'a's if possible, but ensure no 'aaa'
                if a >= 3:
                    result.append('aa')
                    a -= 2
                else:
                    result.append('a')
                    a -= 1
            else:
                # Add two 'b's if possible, but ensure no 'bbb'
                if b >= 3:
                    result.append('bb')
                    b -= 2
                else:
                    result.append('b')
                    b -= 1
        return ''.join(result)
