from typing import List
from collections import defaultdict
import heapq

class Solution:
    def minCost(self, maxTime: int, edges: List[List[int]], passingFees: List[int]) -> int:
        n = len(passingFees)
        # Build adjacency list
        graph = defaultdict(list)
        for u, v, t in edges:
            graph[u].append((v, t))
            graph[v].append((u, t))

        # Priority queue: (cost, time, city)
        # We use (cost, time, city) as the key to prioritize by cost first
        pq = [(passingFees[0], 0, 0)]
        # visited: (city, time) -> min_cost
        visited = {}

        while pq:
            cost, time, city = heapq.heappop(pq)
            if city == n - 1:
                return cost
            if (city, time) in visited:
                if visited[(city, time)] <= cost:
                    continue
            visited[(city, time)] = cost
            for neighbor, t in graph[city]:
                new_time = time + t
                if new_time > maxTime:
                    continue
                new_cost = cost + passingFees[neighbor]
                if (neighbor, new_time) not in visited or visited[(neighbor, new_time)] > new_cost:
                    heapq.heappush(pq, (new_cost, new_time, neighbor))

        return -1
