from typing import List

class Solution:
    def minScoreTriangulation(self, values: List[int]) -> int:
        n = len(values)
        # dp[i][j] represents the minimum score to triangulate the polygon formed by vertices i to j
        dp = [[0] * n for _ in range(n)]

        # Length of the side (number of vertices in the polygon segment)
        for length in range(2, n):
            for i in range(n - length):
                j = i + length
                dp[i][j] = float('inf')
                # k is the vertex that splits the polygon into two parts
                for k in range(i + 1, j):
                    cost = dp[i][k] + dp[k][j] + values[i] * values[k] * values[j]
                    if cost < dp[i][j]:
                        dp[i][j] = cost
        return dp[0][n - 1]
