class Solution:
    def minCut(self, s: str) -> int:
        n = len(s)
        if n == 0:
            return 0

        # dp[i] will hold the minimum cuts for the substring s[0..i]
        dp = [0] * n
        # is_pal[i][j] will be True if s[i..j] is a palindrome
        is_pal = [[False] * n for _ in range(n)]

        # Fill is_pal table
        for i in range(n-1, -1, -1):
            for j in range(i, n):
                if i == j:
                    is_pal[i][j] = True
                elif s[i] == s[j]:
                    if j - i == 1:
                        is_pal[i][j] = True
                    else:
                        is_pal[i][j] = is_pal[i+1][j-1]

        # Fill dp table
        for i in range(n):
            min_cut = i  # Maximum possible cuts for s[0..i] is i
            for j in range(i+1):
                if is_pal[j][i]:
                    if j == 0:
                        min_cut = 0
                    else:
                        min_cut = min(min_cut, dp[j-1] + 1)
            dp[i] = min_cut

        return dp[n-1]
