class Solution:
    def colorTheGrid(self, m: int, n: int) -> int:
        MOD = 10**9 + 7

        # All possible colorings for a single row of m cells
        # Each cell can be 0, 1, or 2 (representing red, green, blue)
        # We generate all valid colorings where adjacent cells are different
        from itertools import product

        # Generate all valid color patterns for a row of m cells
        valid_states = []
        for colors in product(range(3), repeat=m):
            valid = True
            for i in range(m - 1):
                if colors[i] == colors[i + 1]:
                    valid = False
                    break
            if valid:
                valid_states.append(colors)

        # Now we use dynamic programming
        # dp[i][s] = number of ways to color the first i columns with state s at the end
        # We'll use a dictionary for the current and next state counts

        # Initial state: first column
        dp_prev = {state: 1 for state in valid_states}

        for col in range(1, n):
            dp_curr = {}
            for state in valid_states:
                count = 0
                for prev_state in valid_states:
                    # Check if adjacent cells in the same column are different
                    if all(state[i] != prev_state[i] for i in range(m)):
                        count += dp_prev.get(prev_state, 0)
                        count %= MOD
                dp_curr[state] = count
            dp_prev = dp_curr

        # Sum all the possible states for the last column
        return sum(dp_prev.values()) % MOD
