from typing import List
from collections import defaultdict

class Solution:
    def maximumCost(self, n: int, highways: List[List[int]], k: int) -> int:
        # Build the graph
        graph = defaultdict(list)
        for city1, city2, toll in highways:
            graph[city1].append((city2, toll))
            graph[city2].append((city1, toll))

        # We need to find the maximum cost of a path that uses exactly k edges
        # and visits each city at most once.

        # We'll use dynamic programming with states (current city, visited cities, steps taken)
        # Since n <= 15, we can represent visited cities with a bitmask

        max_cost = -1
        # dp[bitmask][current_city] = max cost to reach current_city with that bitmask
        dp = [ [-1] * n for _ in range(1 << n) ]

        # Initialize all starting cities
        for city in range(n):
            dp[1 << city][city] = 0

        # Iterate over number of steps (from 0 to k)
        for steps in range(k):
            # For each possible bitmask and city
            for mask in range(1 << n):
                for city in range(n):
                    if not (mask & (1 << city)):
                        continue
                    if dp[mask][city] == -1:
                        continue
                    # Try to go to all adjacent cities
                    for neighbor, toll in graph[city]:
                        if mask & (1 << neighbor):
                            continue
                        new_mask = mask | (1 << neighbor)
                        new_cost = dp[mask][city] + toll
                        if dp[new_mask][neighbor] < new_cost:
                            dp[new_mask][neighbor] = new_cost

        # Find the maximum cost among all paths with exactly k steps
