from collections import Counter

class Solution:
    def findPairs(self, nums: List[int], k: int) -> int:
        if k < 0:
            return 0

        count = Counter(nums)
        unique_nums = list(count.keys())
        result = 0

        for num in unique_nums:
            if num + k in count:
                if k == 0:
                    # For k = 0, we need at least two occurrences of the same number
                    if count[num] >= 2:
                        result += 1
                else:
                    result += 1

        return result
