from typing import List
from collections import deque

class Solution:
    def magnificentSets(self, n: int, edges: List[List[int]]) -> int:
        # Build adjacency list
        graph = [[] for _ in range(n + 1)]
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        # Helper function to compute max groups using BFS
        def max_groups(start):
            visited = [False] * (n + 1)
            queue = deque()
            queue.append((start, 1))
            visited[start] = True
            count = 0
            while queue:
                node, level = queue.popleft()
                count = max(count, level)
                for neighbor in graph[node]:
                    if not visited[neighbor]:
                        visited[neighbor] = True
                        queue.append((neighbor, level + 1))
            return count

        # Check for bipartition (to avoid odd-length cycles)
        color = [0] * (n + 1)
        is_bipartite = True
        for i in range(1, n + 1):
            if color[i] == 0:
                queue = deque()
                queue.append(i)
                color[i] = 1
                while queue:
                    node = queue.popleft()
                    for neighbor in graph[node]:
                        if color[neighbor] == 0:
                            color[neighbor] = -color[node]
                            queue.append(neighbor)
                        elif color[neighbor] == color[node]:
                            is_bipartite = False

        if not is_bipartite:
            return -1

        # Calculate maximum groups for each starting node
        max_total = 0
        for i in range(1, n + 1):
            max_total = max(max_total, max_groups(i))

        return max_total
