class Solution:
    def removeComments(self, source: List[str]) -> List[str]:
        result = []
        in_block_comment = False
        for line in source:
            if not in_block_comment:
                new_line = []
                i = 0
                while i < len(line):
                    if line[i:i+2] == '/*':
                        in_block_comment = True
                        i += 2
                    elif line[i:i+2] == '//':
                        break
                    else:
                        new_line.append(line[i])
                        i += 1
            else:
                i = 0
                while i < len(line):
                    if line[i:i+2] == '*/':
                        in_block_comment = False
                        i += 2
                    else:
                        i += 1
            if not in_block_comment and new_line:
                result.append(''.join(new_line))
        return result
