class Solution:
    def findDifferentBinaryString(self, nums: List[str]) -> str:
        n = len(nums)
        # Convert each binary string to an integer
        nums_set = set(int(num, 2) for num in nums)

        # Find the first missing integer in the range [0, 2^n - 1]
        for i in range(2 ** n):
            if i not in nums_set:
                # Convert the integer back to binary string of length n
                return bin(i)[2:].zfill(n)

        # This line is theoretically unreachable since there's always a missing number
        return ""
