            current_freq = {}
            for j in range(i, n):
                num = nums[j]
                if num in current_freq:
                    current_freq[num] += 1
                else:
                    current_freq[num] = 1
                # The number of distinct elements is the size of the frequency map
                result = (result + len(current_freq) * len(current_freq)) % MOD

