from typing import List

class Solution:
    def maxTurbulenceSize(self, arr: List[int]) -> int:
        n = len(arr)
        if n == 1:
            return 1

        max_len = 1
        current_len = 1
        prev_diff = 0  # 0: equal, 1: up, -1: down

        for i in range(1, n):
            diff = 0
            if arr[i] > arr[i-1]:
                diff = 1
            elif arr[i] < arr[i-1]:
                diff = -1
            else:
                diff = 0

            if diff == 0:
                current_len = 1
            elif diff == -prev_diff:
                current_len += 1
            else:
                current_len = 2

            max_len = max(max_len, current_len)
            prev_diff = diff

        return max_len
