from typing import List, Set, Dict, Tuple
from collections import defaultdict, deque

class Solution:
    def isPrintable(self, targetGrid: List[List[int]]) -> bool:
        m, n = len(targetGrid), len(targetGrid[0])
        color_set = set()
        for row in targetGrid:
            for color in row:
                color_set.add(color)

        color_to_min_row = {}
        color_to_max_row = {}
        color_to_min_col = {}
        color_to_max_col = {}

        for color in color_set:
            color_to_min_row[color] = m
            color_to_max_row[color] = -1
            color_to_min_col[color] = n
            color_to_max_col[color] = -1

        for i in range(m):
            for j in range(n):
                color = targetGrid[i][j]
                color_to_min_row[color] = min(color_to_min_row[color], i)
                color_to_max_row[color] = max(color_to_max_row[color], i)
                color_to_min_col[color] = min(color_to_min_col[color], j)
                color_to_max_col[color] = max(color_to_max_col[color], j)

        # Build graph for dependencies
        color_graph = defaultdict(set)
        color_in_degree = defaultdict(int)

        # For each color, check if there is any other color that must be printed after it
        for color in color_set:
            min_r, max_r, min_c, max_c = color_to_min_row[color], color_to_max_row[color], color_to_min_col[color], color_to_max_col[color]
            for i in range(min_r, max_r + 1):
                for j in range(min_c, max_c + 1):
                    other_color = targetGrid[i][j]
                    if other_color != color:
                        if other_color not in color_graph[color]:
                            color_graph[color].add(other_color)
                            color_in_degree[other_color] += 1

        # Now perform topological sort
        queue = deque()
        for color in color_set:
            if color_in_degree[color] == 0:
                queue.append(color)

        visited = set()
        while queue:
            current_color = queue.popleft()
            visited.add(current_color)
            for neighbor in color_graph[current_color]:
                color_in_degree[neighbor] -= 1
                if color_in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # If all colors are visited, it's possible
        return len(visited) == len(color_set)

