class Solution:
    def largestSubmatrix(self, matrix: List[List[int]]) -> int:
        m, n = len(matrix), len(matrix[0])
        # Create a copy to avoid modifying the original matrix
        heights = [0] * n
        max_area = 0

        for i in range(m):
            # Update heights for each row
            for j in range(n):
                if matrix[i][j] == 1:
                    heights[j] += 1
                else:
                    heights[j] = 0
            # Sort the heights to find the largest rectangle
            sorted_heights = sorted(heights)
            # Calculate the area for each possible height
            for j in range(n):
                area = sorted_heights[j] * (j + 1)
                max_area = max(max_area, area)

        return max_area
