from typing import List
from collections import deque

class Solution:
    def shortestDistance(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        buildings = []
        dirs = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        total_distance = [[0] * n for _ in range(m)]
        reachable = [[0] * n for _ in range(m)]

        # Collect all buildings
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    buildings.append((i, j))

        # BFS from each building
        for building in buildings:
            queue = deque()
            queue.append((building[0], building[1], 0))
            visited = [[False] * n for _ in range(m)]
            visited[building[0]][building[1]] = True
            while queue:
                x, y, dist = queue.popleft()
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny] and grid[nx][ny] == 0:
                        visited[nx][ny] = True
                        total_distance[nx][ny] += dist + 1
                        reachable[nx][ny] += 1
                        queue.append((nx, ny, dist + 1))

        # Find the empty land that can reach all buildings with minimal total distance
        result = -1
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 0 and reachable[i][j] == len(buildings):
                    result = max(result, total_distance[i][j])

        return result
