from collections import defaultdict, deque
from typing import List

class Solution:
    def alienOrder(self, words: List[str]) -> str:
        # Build the graph (adjacency list)
        graph = defaultdict(list)
        # Build in-degree count
        in_degree = defaultdict(int)

        # Initialize all characters
        all_chars = set()
        for word in words:
            for c in word:
                all_chars.add(c)

        # Compare adjacent words to get ordering
        for i in range(len(words) - 1):
            word1 = words[i]
            word2 = words[i + 1]

            # Find the first differing character
            min_len = min(len(word1), len(word2))
            for j in range(min_len):
                c1 = word1[j]
                c2 = word2[j]
                if c1 != c2:
                    # Add an edge from c1 to c2
                    if c2 not in graph[c1]:
                        graph[c1].append(c2)
                        in_degree[c2] += 1
                    break
            else:
                # If one word is a prefix of the other, and the first is longer, it's invalid
                if len(word1) > len(word2):
                    return ""

        # Initialize the queue with nodes of in-degree 0
        queue = deque([c for c in all_chars if in_degree[c] == 0])
        result = []

        while queue:
            node = queue.popleft()
            result.append(node)
            for neighbor in graph[node]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # If the result doesn't contain all characters, there's a cycle
        if len(result) != len(all_chars):
            return ""

        return ''.join(result)
