class Solution:
    def alphabetBoardPath(self, target: str) -> str:
        # The board is defined as a list of strings
        board = ["abcde", "fghij", "klmno", "pqrst", "uvwxy", "z"]

        # Find the position of each character in the board
        pos = {}
        for i in range(len(board)):
            for j in range(len(board[i])):
                pos[board[i][j]] = (i, j)

        res = []
        curr_r, curr_c = 0, 0  # Starting position (0, 0)

        for char in target:
            target_r, target_c = pos[char]

            # Move vertically first to avoid going out of bounds for 'z'
            # Move up/down
            if curr_r < target_r:
                res.append('D' * (target_r - curr_r))
            elif curr_r > target_r:
                res.append('U' * (curr_r - target_r))

            # Move left/right
            if curr_c < target_c:
                res.append('R' * (target_c - curr_c))
            elif curr_c > target_c:
                res.append('L' * (curr_c - target_c))

            # Append the '!' to add the character
            res.append('!')

            # Update current position
            curr_r, curr_c = target_r, target_c

        return ''.join(res)
