from typing import List

class Solution:
    def countBadPairs(self, nums: List[int]) -> int:
        n = len(nums)
        total_pairs = n * (n - 1) // 2  # Total possible pairs (i, j) with i < j

        # Use a dictionary to count good pairs
        good_pairs = {}
        for i in range(n):
            key = nums[i] - i
            if key in good_pairs:
                good_pairs[key] += 1
            else:
                good_pairs[key] = 1

        # Calculate the number of good pairs
        count_good = 0
        for count in good_pairs.values():
            count_good += count * (count - 1) // 2

        # Bad pairs = total pairs - good pairs
        return total_pairs - count_good
