from typing import List

class Solution:
    def xorGame(self, nums: List[int]) -> bool:
        total_xor = 0
        for num in nums:
            total_xor ^= num

        if total_xor == 0:
            return True  # Alice wins immediately

        # If there's only one number left, Alice will lose if it's non-zero
        if len(nums) == 1:
            return False

        # Count frequency of each number
        from collections import Counter
        count = Counter(nums)

        # If there's a number that appears exactly once, Alice can win by removing it
        for num in count:
            if count[num] == 1:
                return True

        # If all numbers appear even times, Alice can win by removing one of them
        # because the XOR will be zero after removing it
        return False
