class Solution:
    def maxOperations(self, s: str) -> int:
        count = 0
        i = 0
        n = len(s)

        while i < n - 1:
            if s[i] == '1' and s[i + 1] == '0':
                # Move the '1' to the right until it hits another '1' or the end
                j = i
                while j + 1 < n and s[j + 1] == '0':
                    j += 1
                count += 1
                # Move the '1' to the right by one position (simulate the operation)
                # We can simulate this by just moving the pointer, not modifying the string
                i = j
            else:
                i += 1

        return count
