from typing import List

class Solution:
    def widestPairOfIndices(self, nums1: List[int], nums2: List[int]) -> int:
        prefix_sum1 = [0] * (len(nums1) + 1)
        prefix_sum2 = [0] * (len(nums2) + 1)

        for i in range(len(nums1)):
            prefix_sum1[i + 1] = prefix_sum1[i] + nums1[i]
            prefix_sum2[i + 1] = prefix_sum2[i] + nums2[i]

        max_length = 0
        diff_map = {}

        for i in range(len(prefix_sum1)):
            diff = prefix_sum1[i] - prefix_sum2[i]
            if diff in diff_map:
                max_length = max(max_length, i - diff_map[diff])
            else:
                diff_map[diff] = i

        return max_length
