class Solution:
    def areSentencesSimilarTwo(self, sentence1: List[str], sentence2: List[str], similarPairs: List[List[str]]) -> bool:
        if len(sentence1) != len(sentence2):
            return False

        # Union-Find (Disjoint Set Union) setup
        parent = {}

        def find(word):
            if parent[word] != word:
                parent[word] = find(parent[word])  # Path compression
            return parent[word]

        def union(word1, word2):
            root1 = find(word1)
            root2 = find(word2)
            if root1 != root2:
                parent[root2] = root1

        # Initialize parent for all words in similarPairs
        for a, b in similarPairs:
            if a not in parent:
                parent[a] = a
            if b not in parent:
                parent[b] = b
            union(a, b)

        # Check each pair of words
        for w1, w2 in zip(sentence1, sentence2):
            if w1 == w2:
                continue
            # If either word is not in parent, they are not similar
            if w1 not in parent or w2 not in parent:
                return False
            if find(w1) != find(w2):
                return False

        return True
