from typing import List

class Solution:
    def minDominoRotations(self, tops: List[int], bottoms: List[int]) -> int:
        n = len(tops)
        # Try each candidate for the target value (from 1 to 6)
        for target in range(1, 7):
            top_count = 0
            bottom_count = 0
            # Check if the target can be achieved by making all tops or all bottoms equal to target
            for i in range(n):
                if tops[i] == target:
                    top_count += 1
                elif bottoms[i] == target:
                    bottom_count += 1
                else:
                    # If neither top nor bottom is target, it's impossible
                    break
            else:
                # If we completed the loop without breaking, calculate the minimum rotations
                # If all tops are target, then we need to rotate the bottoms that are not target
                # If all bottoms are target, then we need to rotate the tops that are not target
                # If both are possible, take the minimum
                if top_count == n:
                    return n - top_count
                elif bottom_count == n:
                    return n - bottom_count
                else:
                    # This case shouldn't happen because we checked the loop above
                    return -1
        return -1
