from typing import List

class Solution:
    def shortestSubstrings(self, arr: List[str]) -> List[str]:
        n = len(arr)
        # Create a set of all substrings from all other strings
        other_substrings = set()
        for i in range(n):
            for j in range(i + 1, n):
                for substr in self.get_all_substrings(arr[j]):
                    other_substrings.add(substr)

        answer = []
        for s in arr:
            # Find all possible substrings of s, ordered by length then lex order
            candidates = []
            for l in range(1, len(s) + 1):
                for i in range(len(s) - l + 1):
                    substr = s[i:i+l]
                    if substr not in other_substrings:
                        candidates.append(substr)
            if not candidates:
                answer.append("")
            else:
                answer.append(min(candidates))
        return answer

    def get_all_substrings(self, s: str) -> List[str]:
        substrings = set()
        for i in range(len(s)):
            for j in range(i + 1, len(s) + 1):
                substrings.add(s[i:j])
        return substrings
