class Solution:
    def constructDistancedSequence(self, n: int) -> List[int]:
        result = [0] * (2 * n - 1)
        used = [False] * (n + 1)

        def backtrack(pos):
            if pos == len(result):
                return True
            if result[pos] != 0:
                return backtrack(pos + 1)

            for i in range(1, n + 1):
                if used[i]:
                    continue
                if i == 1:
                    # Only one occurrence of 1
                    result[pos] = i
                    used[i] = True
                    if backtrack(pos + 1):
                        return True
                    used[i] = False
                    result[pos] = 0
                else:
