                    if pos + i < len(result) and result[pos + i] == 0:
                        result[pos] = i
                        result[pos + i] = i
                        used[i] = True
                        if backtrack(pos + 1):
                            return True
                        used[i] = False
                        result[pos] = 0
                        result[pos + i] = 0
            return False

