class Solution:
    def sumOfBeauties(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 3:
            return 0

        # Precompute the minimum from the left (exclusive)
        left_min = [0] * n
        left_min[0] = nums[0]
        for i in range(1, n):
            left_min[i] = min(left_min[i-1], nums[i])

        # Precompute the minimum from the right (exclusive)
        right_min = [0] * n
        right_min[n-1] = nums[n-1]
        for i in range(n-2, -1, -1):
            right_min[i] = min(right_min[i+1], nums[i])

        # Now iterate through the array to calculate beauty
        total_beauty = 0
        for i in range(1, n-1):
            # Check condition for beauty 2
            if nums[i] > left_min[i] and nums[i] < right_min[i]:
                total_beauty += 2
            else:
                # Check condition for beauty 1
                if nums[i-1] < nums[i] < nums[i+1]:
                    total_beauty += 1

        return total_beauty
