from typing import List
from collections import defaultdict, deque

class Solution:
    def alienOrder(self, words: List[str]) -> str:
        # Build the graph (adjacency list)
        graph = defaultdict(set)
        # Build in-degree count
        in_degree = defaultdict(int)
        # Set of all unique characters
        all_chars = set()

        # Step 1: Build graph from word comparisons
        for i in range(len(words) - 1):
            word1 = words[i]
            word2 = words[i + 1]
            min_len = min(len(word1), len(word2))
            # Find the first differing character
            for j in range(min_len):
                c1, c2 = word1[j], word2[j]
                if c1 != c2:
                    # Add edge from c1 to c2
                    if c2 not in graph[c1]:
                        graph[c1].add(c2)
                        in_degree[c2] += 1
                    break
            # If word1 is a prefix of word2, and word1 is longer than word2, it's invalid
            if len(word1) > len(word2) and word1[:min_len] == word2[:min_len]:
                return ""

            # Add all characters to all_chars
            for c in word1:
                all_chars.add(c)
            for c in word2:
                all_chars.add(c)

        # Step 2: Topological sort using Kahn's algorithm
        queue = deque([char for char in all_chars if in_degree.get(char, 0) == 0])
        result = []

        while queue:
            node = queue.popleft()
            result.append(node)
            for neighbor in graph[node]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # If the result contains all unique characters, return it, else return ""
        if len(result) == len(all_chars):
            return ''.join(result)
        else:
            return ""
