class Solution:
    def equationsPossible(self, equations: List[str]) -> bool:
        parent = {}

        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            root_x = find(x)
            root_y = find(y)
            if root_x != root_y:
                parent[root_x] = root_y

        # Initialize parent for all variables
        for eq in equations:
            var1 = eq[0]
            var2 = eq[3]
            if var1 not in parent:
                parent[var1] = var1
            if var2 not in parent:
                parent[var2] = var2

        # Process all equality equations first
        for eq in equations:
            if eq[1] == '=':
                var1 = eq[0]
                var2 = eq[3]
                union(var1, var2)

        # Check all inequality equations
        for eq in equations:
            if eq[1] == '!':
                var1 = eq[0]
                var2 = eq[3]
                if find(var1) == find(var2):
                    return False

        return True
