from typing import List

class Solution:
    def subarrayBitwiseORs(self, arr: List[int]) -> int:
        # To store the set of OR results for each position
        prev_or_results = set()
        # To store the final result
        result = set()

        for num in arr:
            # For each new number, compute OR with previous results
            current_or_results = {num}
            for prev_or in prev_or_results:
                current_or_results.add(prev_or | num)
            # Update the result with current OR results
            result.update(current_or_results)
            # Move to the next position, update prev_or_results
            prev_or_results = current_or_results

        return len(result)
