class Solution:
    def findMaximumXOR(self, nums: List[int]) -> int:
        max_num = max(nums)
        mask = 0
        prefix = 0
        trie = {}

        for i in range(31, -1, -1):
            mask |= (1 << i)
            prefix = (max_num & mask)

            # Build trie
            trie = {}
            for num in nums:
                curr = trie
                for j in range(31, -1, -1):
                    bit = (num & (1 << j)) >> j
                    if bit not in curr:
                        curr[bit] = {}
                    curr = curr[bit]

            # Find max XOR
            max_xor = 0
            for num in nums:
                curr = trie
                for j in range(31, -1, -1):
                    bit = (num & (1 << j)) >> j
                    toggle_bit = 1 - bit
                    if toggle_bit in curr:
                        max_xor |= (1 << j)
                        curr = curr[toggle_bit]
                    else:
                        curr = curr[bit]

            max_num = max_xor

        return max_num
