class Solution:
    def minimumNumbers(self, num: int, k: int) -> int:
        if num == 0:
            return 0

        # We need to find the minimum number of numbers with units digit k that sum to num
        # Let's try all possible counts from 1 to num // k (since each number is at least k)
        # For each count, check if (count * k) <= num and (num - count * k) is divisible by 10
        # Because the remaining part after subtracting count * k must be a multiple of 10 to be formed by adding more numbers with units digit k

        for count in range(1, num // k + 1):
            if (num - count * k) % 10 == 0:
                return count

        return -1
