class Solution:
    def numSpecialEquivGroups(self, words: List[str]) -> int:
        from collections import defaultdict

        groups = defaultdict(int)
        for word in words:
            even_chars = ''.join(sorted(word[::2]))
            odd_chars = ''.join(sorted(word[1::2]))
            key = (even_chars, odd_chars)
            groups[key] += 1

        return len(groups)
