class Solution:
    def numberOfPaths(self, n: int, corridors: List[List[int]]) -> int:
        # Build adjacency list
        from collections import defaultdict

        graph = defaultdict(set)
        for u, v in corridors:
            graph[u].add(v)
            graph[v].add(u)

        count = 0

        # Iterate through each node as a starting point
        for start in range(1, n + 1):
            visited = set()
            stack = [(start, None, 0)]  # (current_node, previous_node, depth)

            while stack:
                node, prev, depth = stack.pop()
                if node in visited:
                    continue
                visited.add(node)
                if depth == 2:
                    # We have a cycle of length 3
                    count += 1
                else:
                    for neighbor in graph[node]:
                        if neighbor != prev:
                            stack.append((neighbor, node, depth + 1))

        return count
