from collections import deque

class Solution:
    def collectTheCoins(self, coins: List[int], edges: List[List[int]]) -> int:
        n = len(coins)
        if n == 0:
            return 0

        # Build the tree as an adjacency list
        graph = [[] for _ in range(n)]
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        # Step 1: Remove all leaf nodes with no coins (prune the tree)
        # We perform a BFS to find all leaves and remove them
        # We also need to track the number of times we prune to avoid infinite loops
        def prune():
            leaves = deque()
            degree = [len(adj) for adj in graph]
            for i in range(n):
                if degree[i] == 1 and coins[i] == 0:
                    leaves.append(i)

            removed = 0
            while leaves:
                u = leaves.popleft()
                for v in graph[u]:
                    if degree[v] > 1:
                        degree[v] -= 1
                        if degree[v] == 1 and coins[v] == 0:
                            leaves.append(v)
                removed += 1
                graph[u].clear()

            return removed

        # Prune the tree until we can't prune anymore
        while True:
            removed = prune()
            if removed == 0:
                break

        # Step 2: Count the number of edges in the pruned tree
        # We can do this with BFS or DFS
        def count_edges():
            visited = [False] * n
            total = 0
            for i in range(n):
                if len(graph[i]) > 0 and not visited[i]:
                    stack = [i]
                    visited[i] = True
                    while stack:
                        node = stack.pop()
                        for neighbor in graph[node]:
                            if not visited[neighbor]:
                                visited[neighbor] = True
                                stack.append(neighbor)
                                total += 1
            return total

        # The answer is the total number of edges in the pruned tree
        # But since we can collect coins from distance 2, we need to consider
        # that we can collect coins from up to two levels away, so we need to
        # remove all nodes that are at distance > 2 from any coin
        # This is a bit more complex, but we can use BFS again to find all nodes
        # that are at distance 2 from any coin and prune them

        # First, find all nodes with coins
        coin_nodes = [i for i in range(n) if coins[i] == 1]
        if not coin_nodes:
            return 0

        # BFS to find all nodes at distance <= 2 from any coin
        visited = [False] * n
        q = deque()
        for node in coin_nodes:
            q.append((node, 0))
            visited[node] = True

        while q:
            node, dist = q.popleft()
            if dist == 2:
                continue
            for neighbor in graph[node]:
                if not visited[neighbor]:
                    visited[neighbor] = True
                    q.append((neighbor, dist + 1))

        # Now, we remove all nodes that are not visited (i.e., not within 2 of a coin)
        # and update the graph
        for i in range(n):
            if not visited[i]:
                for neighbor in graph[i]:
                    if visited[neighbor]:
                        graph[neighbor].remove(i)
                graph[i].clear()

        # Now, count the number of edges in the pruned graph
        total_edges = 0
        visited = [False] * n
        for i in range(n):
            if len(graph[i]) > 0 and not visited[i]:
                stack = [i]
                visited[i] = True
                while stack:
                    node = stack.pop()
                    for neighbor in graph[node]:
                        if not visited[neighbor]:
                            visited[neighbor] = True
                            stack.append(neighbor)
                            total_edges += 1

        # The answer is twice the number of edges (since we need to go back)
        return total_edges // 2 if total_edges else 0
