class Solution:
    def canChange(self, start: str, target: str) -> bool:
        i = j = 0
        n = len(start)
        while i < n and j < n:
            # Skip underscores in both strings
            while i < n and start[i] == '_':
                i += 1
            while j < n and target[j] == '_':
                j += 1

            # If one has a character and the other doesn't, return False
            if i < n and j < n:
                if start[i] != target[j]:
                    return False
                # Check if the position in start is valid for the character in target
                # For 'L', it can only move left (so in start, it must be at a position >= target's position)
                # For 'R', it can only move right (so in start, it must be at a position <= target's position)
                if start[i] == 'L' and i < j:
                    return False
                if start[i] == 'R' and i > j:
                    return False
                i += 1
                j += 1
            else:
                break

        # After processing all characters, check if the remaining are all underscores
        # But since we've already skipped underscores, the rest must be all underscores
        # So, if we reached the end of both, it's valid
        return True
