from typing import List

class Solution:
    def invalidTransactions(self, transactions: List[str]) -> List[str]:
        # Parse transactions into a list of dictionaries for easier access
        parsed = []
        for t in transactions:
            name, time, amount, city = t.split(',')
            parsed.append({
                'name': name,
                'time': int(time),
                'amount': int(amount),
                'city': city,
                'original': t
            })

        invalid = set()

        # Check for amount exceeding 1000
        for t in parsed:
            if t['amount'] > 1000:
                invalid.add(t['original'])

        # Check for transactions in different cities within 60 minutes
        for i, t1 in enumerate(parsed):
            for j, t2 in enumerate(parsed):
                if i == j:
                    continue
                if t1['name'] != t2['name']:
                    continue
                if t1['city'] == t2['city']:
                    continue
                if abs(t1['time'] - t2['time']) <= 60:
                    invalid.add(t1['original'])
                    invalid.add(t2['original'])

        return list(invalid)
