class Solution:
    def firstMissingPositive(self, nums: List[int]) -> int:
        n = len(nums)
        for i in range(n):
            # Ensure the number is within the range [1, n]
            while 1 <= nums[i] <= n and nums[nums[i] - 1] != nums[i]:
                # Swap nums[i] to its correct position
                correct_pos = nums[i] - 1
                nums[i], nums[correct_pos] = nums[correct_pos], nums[i]

        # After rearrangement, find the first index where the value is not index + 1
        for i in range(n):
            if nums[i] != i + 1:
                return i + 1
        return n
