from typing import List
from collections import deque

class Solution:
    def shortestDistance(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])
        buildings = []
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    buildings.append((i, j))

        # Directions for up, down, left, right
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

        # For each building, perform BFS and accumulate distances
        # Also track how many buildings can reach each empty land
        total_distances = [[0] * n for _ in range(m)]
        reachable_count = [[0] * n for _ in range(m)]

        for build_x, build_y in buildings:
            queue = deque()
            queue.append((build_x, build_y, 0))
            visited = [[False] * n for _ in range(m)]
            visited[build_x][build_y] = True
            while queue:
                x, y, dist = queue.popleft()
                for dx, dy in directions:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny]:
                        if grid[nx][ny] == 0:
                            total_distances[nx][ny] += dist + 1
                            reachable_count[nx][ny] += 1
                            visited[nx][ny] = True
                            queue.append((nx, ny, dist + 1))
                        elif grid[nx][ny] == 1:
                            # Building, do not go further
                            pass
                        else:
                            # Obstacle, do not go further
                            pass

        # Find the empty land that can reach all buildings with minimal total distance
        result = -1
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 0 and reachable_count[i][j] == len(buildings):
                    result = max(result, total_distances[i][j])

        return result
