from typing import List

class Solution:
    def findMedianSortedArrays(self, nums1: List[int], nums2: List[int]) -> float:
        # Ensure nums1 is the shorter array to optimize the binary search
        if len(nums1) > len(nums2):
            nums1, nums2 = nums2, nums1

        m, n = len(nums1), len(nums2)
        left, right = 0, m

        while left <= right:
            # Partition nums1
            partition1 = (left + right) // 2
            # Partition nums2
            partition2 = (m + n + 1) // 2 - partition1

            # Handle edge cases for out-of-bound indices
            max1 = nums1[partition1 - 1] if partition1 > 0 else float('-inf')
            min1 = nums1[partition1] if partition1 < m else float('inf')
            max2 = nums2[partition2 - 1] if partition2 > 0 else float('-inf')
            min2 = nums2[partition2] if partition2 < n else float('inf')

            # Check if the partitions are correct
            if max1 <= min2 and max2 <= min1:
                # Found the correct partition
                if (m + n) % 2 == 0:
                    return (max(max1, max2) + min(min1, min2)) / 2
                else:
                    return max(max1, max2)
            elif max1 > min2:
                # Move partition1 to the left
                right = partition1 - 1
            else:
                # Move partition1 to the right
                left = partition1 + 1
