class Solution:
    def countWays(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        res = 0

        # Check for the case where no one is selected
        if nums[0] > 0:
            res += 1

        # Check for the case where all are selected
        if nums[-1] < n:
            res += 1

        # Check for valid k in between
        for i in range(1, n):
            if nums[i-1] < i and nums[i] > i:
                res += 1

