class Solution:
    def robotWithString(self, s: str) -> str:
        from collections import deque

        # Count the frequency of each character
        count = [0] * 26
        for c in s:
            count[ord(c) - ord('a')] += 1

        # Create a deque for the string t
        t = deque()
        result = []

        # Traverse the string s
        for c in s:
            t.append(c)
            # While the top of t is less than or equal to the current smallest available character
            while t and count[ord(t[-1]) - ord('a')] > 0:
                result.append(t.pop())
                count[ord(t[-1]) - ord('a')] -= 1

        # Pop the remaining characters from t
        while t:
            result.append(t.pop())

        return ''.join(result)
