class Solution:
    def isNumber(self, s: str) -> bool:
        # Check if the string is a valid number
        # We will use a state machine approach to parse the string

        # State definitions:
        # 0: Start state
        # 1: Sign (+/-)
        # 2: Integer part (digits)
        # 3: Decimal point
        # 4: Decimal part after point
        # 5: Exponent (e/E)
        # 6: Sign after exponent
        # 7: Integer part after exponent

        state = 0
        for char in s:
            if state == 0:
                if char in "+-":
                    state = 1
                elif char.isdigit():
                    state = 2
                elif char == ".":
                    state = 3
                else:
                    return False
            elif state == 1:
                if char.isdigit():
                    state = 2
                elif char == ".":
                    state = 3
                else:
                    return False
            elif state == 2:
                if char.isdigit():
                    continue
                elif char == ".":
                    state = 3
                elif char in "eE":
                    state = 5
                else:
                    return False
            elif state == 3:
                if char.isdigit():
                    state = 4
                elif char in "eE":
                    state = 5
                else:
                    return False
            elif state == 4:
                if char.isdigit():
                    continue
                elif char in "eE":
                    state = 5
                else:
                    return False
            elif state == 5:
                if char in "+-":
                    state = 6
                elif char.isdigit():
                    state = 7
                else:
                    return False
            elif state == 6:
                if char.isdigit():
                    state = 7
                else:
                    return False
            elif state == 7:
                if char.isdigit():
                    continue
                else:
                    return False
        return state in [2, 3, 4, 7]
