from typing import List

class Solution:
    def canPartitionKSubsets(self, nums: List[int], k: int) -> bool:
        total = sum(nums)
        if total % k != 0:
            return False
        target = total // k
        nums.sort(reverse=True)

        # To avoid duplicate work, we can memoize the state
        # However, since the nums list is small (<=16 elements), we can use backtracking

        # Helper function to backtrack
        def backtrack(start, current_sum, used, count):
            if count == k:
                return True
            if current_sum == target:
                return backtrack(0, 0, used, count + 1)
            for i in range(start, len(nums)):
                if not used[i] and current_sum + nums[i] <= target:
                    if i > 0 and nums[i] == nums[i-1] and not used[i-1]:
                        continue  # Skip duplicates to avoid redundant work
                    used[i] = True
                    if backtrack(i + 1, current_sum + nums[i], used, count):
                        return True
                    used[i] = False
            return False

        used = [False] * len(nums)
        return backtrack(0, 0, used, 0)

