from typing import List
from collections import defaultdict

class Solution:
    def numMatchingSubseq(self, s: str, words: List[str]) -> int:
        # Create a dictionary to map each character to the list of indices where it appears in s
        char_indices = defaultdict(list)
        for idx, char in enumerate(s):
            char_indices[char].append(idx)

        # Function to check if a word is a subsequence of s
        def is_subsequence(word: str) -> bool:
            ptr = 0  # Pointer in s
            for char in word:
                # Find the first occurrence of char in s that is after the current position
                indices = char_indices.get(char, [])
                # Use binary search to find the smallest index in indices that is >= ptr
                left, right = 0, len(indices)
                while left < right:
                    mid = (left + right) // 2
                    if indices[mid] < ptr:
                        left = mid + 1
                    else:
                        right = mid
                if left == len(indices):
                    return False  # Character not found after current position
                ptr = indices[left] + 1  # Move pointer to the next position after the found index
            return True

        # Count the number of words that are a subsequence of s
        count = 0
        for word in words:
            if is_subsequence(word):
                count += 1
        return count
