from typing import List
from functools import lru_cache

class Solution:
    def maxTotalReward(self, rewardValues: List[int]) -> int:
        rewardValues.sort()
        unique_rewards = list(sorted(set(rewardValues)))
        n = len(unique_rewards)

        @lru_cache(None)
        def dfs(i, x):
            if i == n:
                return x
            # Option 1: skip the current reward
            res = dfs(i + 1, x)
            # Option 2: take the current reward if possible
            if unique_rewards[i] > x:
                res = max(res, dfs(i + 1, x + unique_rewards[i]))
            return res

        return dfs(0, 0)
