class Solution:
    def minimumLengthEncoding(self, words: List[str]) -> int:
        # Use a set for faster lookups
        word_set = set(words)

        # Iterate through each word in the set
        for word in word_set:
            # Check if any suffix of the word is also in the set
            for i in range(1, len(word)):
                suffix = word[i:]
                if suffix in word_set:
                    # Remove the suffix as it's already covered
                    word_set.discard(suffix)

        # Each word left in the set needs to be followed by a '#'
        return len(word_set) * 2 + 1
