class Solution:
    def numDupDigitsAtMostN(self, n: int) -> int:
        from math import factorial
        from collections import Counter

        def count_unique_digits(num):
            digits = list(map(int, str(num)))
            length = len(digits)
            count = 0

            # Count numbers with unique digits less than num
            for i in range(1, length):
                count += 9 * 9 * 8 * 7 * 6 * 5 * 4 * 3 * 2 * 1 // (24 * 10 ** (i - 1))  # Permutations of digits

            # Count numbers with unique digits equal to num
            used = [False] * 10
            def backtrack(pos, leading_zero, has_used):
                if pos == length:
                    return 1 if has_used else 0
                res = 0
                for d in range(0, 10):
                    if leading_zero and d == 0:
                        res += backtrack(pos + 1, True, has_used)
                        continue
                    if used[d]:
                        continue
                    if d == digits[pos] and not leading_zero:
                        if has_used:
                            res += backtrack(pos + 1, False, True)
                        else:
                            res += backtrack(pos + 1, False, True)
                    else:
                        used[d] = True
                        res += backtrack(pos + 1, False, has_used or (d != 0))
                        used[d] = False
                return res

            count += backtrack(0, True, False)
            return count

        return n - count_unique_digits(n)
