from typing import List

class Solution:
    def longestWord(self, words: List[str]) -> str:
        # Sort the words by length and lexicographical order
        words.sort(key=lambda x: (len(x), x))
        word_set = set(words)
        max_len = 0
        result = ""

        for word in words:
            # Check if all prefixes of the word are in the set
            valid = True
            for i in range(1, len(word)):
                if word[:i] not in word_set:
                    valid = False
                    break
            if valid:
                if len(word) > max_len or (len(word) == max_len and word < result):
                    max_len = len(word)
                    result = word
        return result
