from typing import List

class Solution:
    def validateBinaryTreeNodes(self, n: int, leftChild: List[int], rightChild: List[int]) -> bool:
        # Step 1: Check for duplicate children
        children = set()
        for child in leftChild + rightChild:
            if child != -1 and child in children:
                return False
            children.add(child)

        # Step 2: Find root node (node with no parent)
        parent_count = [0] * n
        for i in range(n):
            if leftChild[i] != -1:
                parent_count[leftChild[i]] += 1
            if rightChild[i] != -1:
                parent_count[rightChild[i]] += 1

        root = -1
        for i in range(n):
            if parent_count[i] == 0:
                root = i
                break

        if root == -1:
            return False  # No root node found

        # Step 3: Perform BFS to check for cycles and ensure all nodes are visited
        visited = set()
        queue = [root]
        visited.add(root)

        while queue:
            node = queue.pop(0)
            for child in [leftChild[node], rightChild[node]]:
                if child == -1:
                    continue
                if child in visited:
                    return False  # Cycle detected
                visited.add(child)
                queue.append(child)

        # Step 4: Ensure all nodes are visited
        return len(visited) == n
