class Solution:
    def seePeople(self, heights: List[List[int]]) -> List[List[int]]:
        m, n = len(heights), len(heights[0])
        answer = [[0]*n for _ in range(m)]

        # For each cell, check to the right and below
        # Right direction
        for i in range(m):
            for j in range(n-2, -1, -1):
                current = heights[i][j]
                next_j = j + 1
                count = 0
                while next_j < n:
                    if heights[i][next_j] >= current:
                        count += 1
                        break
                    else:
