from typing import List
from collections import defaultdict, deque

class Solution:
    def countSubgraphsForEachDiameter(self, n: int, edges: List[List[int]]) -> List[int]:
        # Build adjacency list
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        # Precompute all possible subsets of nodes (since n <= 15, 2^15 = 32768)
        result = [0] * (n - 1)

        # Iterate through all subsets of nodes
        for mask in range(1, 1 << n):
            nodes = [i + 1 for i in range(n) if (mask >> i) & 1]
            # Check if the subset forms a valid subtree (connected)
            if self.is_connected(nodes, graph):
                # Compute the maximum distance in this subtree
                max_dist = self.compute_max_distance(nodes, graph)
                if max_dist <= n - 1:
                    result[max_dist - 1] += 1

        return result

    def is_connected(self, nodes, graph):
        # Check if the subset of nodes forms a connected subtree
        if not nodes:
            return False
        visited = set()
        queue = [nodes[0]]
        visited.add(nodes[0])
        while queue:
            node = queue.pop(0)
            for neighbor in graph[node]:
                if neighbor in nodes and neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        return len(visited) == len(nodes)

    def compute_max_distance(self, nodes, graph):
        # Compute the maximum distance between any two nodes in the subtree
        # Use BFS to find the diameter of the subtree
        def bfs(start):
            visited = {start: 0}
            queue = deque([start])
            while queue:
                node = queue.popleft()
                for neighbor in graph[node]:
                    if neighbor in nodes and neighbor not in visited:
                        visited[neighbor] = visited[node] + 1
                        queue.append(neighbor)
            return max(visited.values())

        max_dist = 0
        for node in nodes:
            dist = bfs(node)
            max_dist = max(max_dist, dist)
        return max_dist
