class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        def is_special(x):
            # Count the number of proper divisors of x
            count = 0
            for i in range(1, int(x**0.5) + 1):
                if x % i == 0:
                    if i != x:
                        count += 1
                    if x // i != i and x // i != x:
                        count += 1
            return count == 2

        # Since checking each number in [l, r] directly is too slow for large ranges,
        # we can find the count of special numbers by generating all numbers with exactly two proper divisors.
        # A number with exactly two proper divisors must be the square of a prime or the product of two distinct primes.
        # However, for large ranges (up to 1e9), we need a better approach.

        # Instead of checking every number, we can precompute all primes up to sqrt(r),
        # and generate numbers of the form p^2 and p*q (p and q are primes), then count how many of them fall in [l, r]

        # First, find all primes up to sqrt(r) using sieve
        import math
        max_prime = int(math.isqrt(r)) + 1

        # Sieve of Eratosthenes to find all primes up to max_prime
        is_prime = [True] * (max_prime + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(math.isqrt(max_prime)) + 1):
            if is_prime[i]:
                for j in range(i * i, max_prime + 1, i):
                    is_prime[j] = False

        primes = [i for i, val in enumerate(is_prime) if val]

        # Generate all special numbers in [l, r]
        special_numbers = set()

        # Case 1: p^2 (where p is prime)
        for p in primes:
            square = p * p
            if l <= square <= r:
                special_numbers.add(square)

        # Case 2: p * q (where p and q are distinct primes)
        for i in range(len(primes)):
            for j in range(i + 1, len(primes)):
                product = primes[i] * primes[j]
                if l <= product <= r:
                    special_numbers.add(product)

        return r - l + 1 - len(special_numbers)
