from typing import List

class Solution:
    def ambiguousCoordinates(self, s: str) -> List[str]:
        def get_possible_numbers(string: str) -> List[str]:
            n = len(string)
            result = []
            for i in range(1, n):
                # Split into two parts
                left = string[:i]
                right = string[i:]
                # Check left part
                if left[0] == '0' and len(left) > 1:
                    continue  # Skip leading zero
                # Check right part
                if right[-1] == '0' and len(right) > 1:
                    continue  # Skip trailing zero
                # If right has a decimal point, it must have at least one digit before
                if '.' in right:
                    if right.index('.') == 0:
                        continue  # No digit before decimal
                    if right.count('.') > 1:
                        continue  # More than one decimal point
                # Check if right is valid decimal
                if '.' in right:
                    parts = right.split('.')
                    if len(parts[0]) == 0 or len(parts[1]) == 0:
                        continue
                result.append(string)
            return result

        s = s[1:-1]  # Remove the outer parentheses
        result = []
        for i in range(1, len(s)):
            left = s[:i]
            right = s[i:]
            left_numbers = get_possible_numbers(left)
            right_numbers = get_possible_numbers(right)
            for l in left_numbers:
                for r in right_numbers:
                    result.append(f"({l}, {r})")
        return result
