class Solution:
    def longestSubstring(self, s: str, k: int) -> int:
        if len(s) < k:
            return 0

        # Find the first character that appears less than k times
        for c in set(s):
            if s.count(c) < k:
                # Split the string on this character and recursively check each part
                return max(self.longestSubstring(part, k) for part in s.split(c))

        # If all characters appear at least k times, the whole string is valid
        return len(s)
