from typing import List
from collections import defaultdict, deque

class Solution:
    def countSubgraphsForEachDiameter(self, n: int, edges: List[List[int]]) -> List[int]:
        # Build adjacency list
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)
            graph[v].append(u)

        # Function to compute the diameter of a subtree
        def compute_diameter(subtree: set) -> int:
            # Convert subtree to a list for easier handling
            nodes = list(subtree)
            if len(nodes) == 1:
                return 0

            # BFS to find the furthest node from an arbitrary node
            def bfs(start):
                visited = {start}
                queue = deque([(start, 0)])
                max_dist = 0
                farthest_node = start
                while queue:
                    node, dist = queue.popleft()
                    for neighbor in graph[node]:
                        if neighbor not in visited:
                            visited.add(neighbor)
                            queue.append((neighbor, dist + 1))
                            if dist + 1 > max_dist:
                                max_dist = dist + 1
                                farthest_node = neighbor
                return farthest_node, max_dist

            # First BFS to find one end of the longest path
            node1, _ = bfs(next(iter(subtree)))
            # Second BFS to find the other end and get the diameter
            node2, diameter = bfs(node1)
            return diameter

        # Generate all possible non-empty subsets of cities
        result = [0] * (n - 1)
        for mask in range(1, 1 << n):
            subtree = set()
            for i in range(n):
                if mask & (1 << i):
                    subtree.add(i + 1)  # cities are 1-indexed
            if len(subtree) < 2:
                continue
            diameter = compute_diameter(subtree)
            if diameter < n - 1:
                result[diameter] += 1

        return result
