from typing import List

class Solution:
    def matrixScore(self, grid: List[List[int]]) -> int:
        m, n = len(grid), len(grid[0])

        # First, ensure the first column is all 1s by toggling rows if needed
        for i in range(m):
            if grid[i][0] == 0:
                # Toggle the entire row
                grid[i] = [1 - x for x in grid[i]]

        # Now, for each column from index 1 to n-1, count the number of 1s
        # and decide whether to toggle the column to maximize the number of 1s
        for j in range(1, n):
            count = 0
            for i in range(m):
                count += grid[i][j]
            # If the number of 1s is less than half the rows, toggle the column
            if count * 2 < m:
                for i in range(m):
                    grid[i][j] = 1 - grid[i][j]

        # Now calculate the score
        score = 0
        for i in range(m):
            row = grid[i]
            val = 0
            for j in range(n):
                val = val * 2 + row[j]
            score += val

        return score
