class Solution:
    def monotoneIncreasingDigits(self, n: int) -> int:
        # Convert the number to a list of its digits
        digits = list(str(n))
        n = len(digits)

        # Find the first place where the digits are not in increasing order
        i = 0
        while i + 1 < n and digits[i] <= digits[i + 1]:
            i += 1

        # If the digits are already increasing, return the number
        if i == n - 1:
            return int(''.join(digits))

        # Otherwise, find the point where we need to decrease the number
        # and set the rest to 9
        while i > 0 and digits[i] <= digits[i - 1]:
            i -= 1

        # Decrease the digit at position i by 1
        digits[i] = str(int(digits[i]) - 1)

        # Set all digits after i to 9
        for j in range(i + 1, n):
            digits[j] = '9'

        return int(''.join(digits))
